=Write the full 4-touch sequence for this prospect.

## Prospect
{{ $json.first_name }} {{ $json.last_name }} — {{ $json.title }} @ {{ $json.company_name }}

## Use this exact first line in email_1
{{ $json.personalization && $json.personalization.first_line }}

## Prospect Brief
{{ JSON.stringify($json.prospect_brief) }}

## Pain hypothesis
{{ $json.pain_hypothesis }}

Return JSON in this EXACT schema:
{
  "subject_a": "<≤6 words>",
  "subject_b": "<≤6 words, different angle>",
  "email_1": "<≤75 words, no greeting line, no sign-off>",
  "email_2": "<≤50 words>",
  "email_3": "<≤50 words>",
  "email_4": "<≤50 words, breakup>",
  "send_offsets_days": [0, 3, 7, 14],
  "compliance": {
    "spam_trigger_words_found": [],
    "approved": true
  }
}

parameters.jsCode:
const lead = $('When Executed by Parent').item.json;
let seq = $input.first().json;
if (seq && seq.message && seq.message.content) {
  try { seq = typeof seq.message.content === 'string' ? JSON.parse(seq.message.content) : seq.message.content; }
  catch(e) { seq = null; }
}
if (!seq || !seq.email_1) {
  // Fallback: build a minimal compliant sequence
  const fl = lead.personalization && lead.personalization.first_line ? lead.personalization.first_line : '';
  seq = {
    subject_a: 'quick idea for ' + (lead.company_name||'').split(' ')[0],
    subject_b: 'reply rate at ' + (lead.company_name||'').split(' ')[0],
    email_1: fl + ' Most teams your size are losing 30% of pipeline to weak personalization and bad follow-up. DropMeds runs your entire cold-email engine on autopilot. Worth 15 mins to compare notes?',
    email_2: 'Following the thread above — one stat: teams who switch see 2.4× reply rate within 30 days. Open to a quick look?',
    email_3: 'Sharing a 90-second loom showing how the agent personalizes at scale. Useful even if DropMeds isn\'t a fit.',
    email_4: 'Want me to close the loop on this thread? Happy to circle back next quarter if timing is off.',
    send_offsets_days: [0,3,7,14],
    compliance: { spam_trigger_words_found: [], approved: true }
  };
}
return [{ json: { ...lead, sequence: seq } }];
